const dailyLimit = document.getElementById("daily_limit");
const bidAmount = document.getElementById("js-bid-price");

const text = {
    ru: 'Максимум кликов в день: ',
    ro: 'Maximum clickuri pe zi: '
};

const changeClickInfo = (amountToAdd = 0) => {
    const exText = document.querySelector(".bid-counter-container");

    var newElement = document.getElementById('added-p');
    if (!newElement) {
        var newElement = document.createElement('p', {
            id: 'added-p'
        });
        newElement.id = 'added-p';
        newElement.style = "color: #999; font-size: 12px; font-style: normal; font-weight: 400; line-height: normal;"
        var parentElement = exText.parentNode;
        parentElement.insertBefore(newElement, exText.nextSibling);
    }

    const count = Math.round(Number(dailyLimit.value) * 100 / (Number(bidAmount.value) + amountToAdd));
    newElement.innerHTML = text[CONFIG.LOCALE_CODE] + `<span style="color: #333;">${count}</span>`;
}

dailyLimit.addEventListener("change", () => {
    changeClickInfo()
});

const plusCounterButton = document.querySelector('.bid-counter-button-plus');

plusCounterButton.addEventListener('click', () => {
    changeClickInfo(0.20)
})

const minusCounterButton = document.querySelector('.bid-counter-button-minus');

minusCounterButton.addEventListener('click', () => {
    changeClickInfo(-0.20)
})

changeClickInfo()

