// Parameter to control whether the popup should appear on every page load
var showPopup = false; // Set to true to always show the popup, false to show only once

// Check if popup has already been shown
var popupHidden = localStorage.getItem('popupHidden') === 'true';

function createCTABannerTest() {
  // Create the overlay for shadowing the background
  var overlay = document.createElement('div');
  overlay.classList.add('cta-overlay');

  // Create the CTA container div (popup)
  var ctaContainer = document.createElement('div');
  ctaContainer.classList.add('cta-container');

  // Create the text container
  var textContainer = document.createElement('div');

  // Create the headline
  var headline = document.createElement('h2');
  if (document.documentElement.lang === 'ru') {
    headline.textContent = 'Не знаете какой тариф выбрать?';
  }
  if (document.documentElement.lang === 'ro') {
    headline.textContent = 'Nu știți ce tarif să alegeți?';
  }

  // Create headline CTA
  var headlineCTA = document.createElement('h2');
  headlineCTA.className = 'hCTA';
  if (document.documentElement.lang === 'ru') {
    headlineCTA.textContent = 'Попробуйте тариф Pro!';
  }
  if (document.documentElement.lang === 'ro') {
    headlineCTA.textContent = 'Încercați tariful Pro!';
  }

  // Create the subheadline
  var subheadline = document.createElement('p');
  if (document.documentElement.lang === 'ru') {
    subheadline.innerHTML = `
      <span class="subheadline-item">✅ На 35% больше звонков</span>
      <span class="subheadline-item">✅ 20 фотографий в объявлении</span>
      <span class="subheadline-item">✅ 20 000 символов в описании</span>
      <span class="subheadline-item">✅ Бонусы при пополнении счета 
        <img src="https://i.simpalsmedia.com/thumbor/620x0/i.simpalsmedia.com/fotobank/original/82374450e80a9edb21c4dde0e26a9412.png" alt="Bonus Image" style="vertical-align: middle; width: 27px; height: 14px;">
      </span>
      <span class="subheadline-item">✅ Расширенная статистика</span>
    `;
  }
  if (document.documentElement.lang === 'ro') {
    subheadline.innerHTML = `
      <span class="subheadline-item">✅ Cu 35% mai multe apeluri</span>
      <span class="subheadline-item">✅ 20 de fotografii în anunț</span>
      <span class="subheadline-item">✅ 20 000 de caractere în descriere</span>
      <span class="subheadline-item">✅ Bonusuri la alimentarea contului 
        <img src="https://i.simpalsmedia.com/thumbor/620x0/i.simpalsmedia.com/fotobank/original/82374450e80a9edb21c4dde0e26a9412.png" alt="Bonus Image" style="vertical-align: middle; width: 27px; height: 14px;">
      </span>
      <span class="subheadline-item">✅ Statistici extinse</span>
    `;
  }

  // Append headline and subheadline to text container
  textContainer.appendChild(headline);
  textContainer.appendChild(headlineCTA);
  textContainer.appendChild(subheadline);

  // Create the button
  var button = document.createElement('a');
  if (document.documentElement.lang === 'ru') {
    button.textContent = 'Подключить Pro сейчас';
    button.href = 'https://business.999.md/ru/tariffs/?utm_source=999&utm_medium=popup&utm_campaign=gb_popup_pro_ru';
  }
  if (document.documentElement.lang === 'ro') {
    button.textContent = 'Activează Pro acum';
    button.href = 'https://business.999.md/ro/tariffs/?utm_source=999&utm_medium=popup&utm_campaign=gb_popup_pro_ro';
  }
  button.target = '_blank'; // Open link in a new tab
  button.classList.add('cta-button');

  // Set flag when button is clicked
  button.addEventListener('click', function () {
    localStorage.setItem('popupHidden', 'true');
  });

  // Create the close button (X)
  var closeButton = document.createElement('span');
  closeButton.textContent = '×';
  closeButton.classList.add('cta-close');

  // Close functionality
  closeButton.addEventListener('click', function () {
    ctaContainer.style.display = 'none';
    overlay.style.display = 'none'; // Hide the overlay as well

    // Set a flag in localStorage that the popup has been hidden
    localStorage.setItem('popupHidden', 'true');
  });

  // Append everything to the CTA container
  ctaContainer.appendChild(textContainer);
  ctaContainer.appendChild(button);
  ctaContainer.appendChild(closeButton);

  // Append both CTA container and overlay to the body
  document.body.appendChild(overlay);
  overlay.appendChild(ctaContainer); // Popup is part of the overlay
}

// Only create the popup if it hasn't been hidden before or if we want it to appear every time
if (!popupHidden || showPopup) {
  createCTABannerTest();
}

