// Function to handle search input and add a custom suggestion
function handleSearchInput() {
  // Get the search input element
  var searchInput = document.getElementById('js-search-input');

  // Listen for changes in the input
  searchInput.addEventListener('input', function() {
    // Get the search value and convert it to lowercase for case-insensitive matching
    var searchValue = searchInput.value.toLowerCase();

    // Get the suggestions container
    var suggestionsContainer = document.querySelector('.tt-dropdown-menu .tt-dataset');

    // Remove any previous custom suggestion
    var previousCustomSuggestion = document.getElementById('custom-suggestion');
    if (previousCustomSuggestion) {
      previousCustomSuggestion.remove();
    }

    // Check if suggestions are visible and if there are at least three suggestions
    if (suggestionsContainer && suggestionsContainer.children.length >= 3) {
      // Create a custom suggestion element
      var customSuggestion = document.createElement('div');
      customSuggestion.className = 'header__search__suggestion is-simple tt-suggestion tt-selectable';
      customSuggestion.id = 'custom-suggestion';

      // Create the custom suggestion content with text and an image
      var suggestionText = document.createElement('strong');
      suggestionText.className = 'tt-highlight';
      suggestionText.textContent = searchValue; // Use the search input as the text

var suggestionIn = document.createElement('strong');
suggestionIn.textContent = ' в ';

      var suggestionImage = document.createElement('img');
      suggestionImage.src = 'https://i.simpalsmedia.com/thumbor/620x0/i.simpalsmedia.com/fotobank/original/135a1b1e79dbcdbd116ac3e9a863caf4.png'; // Change to your image URL
      suggestionImage.alt = 'Suggested Image';
      suggestionImage.style.width = '78px';
      suggestionImage.style.height = '30px';
      suggestionImage.style.marginLeft = '8px';
      suggestionImage.style.verticalAlign = 'middle';

      // Append the text and image to the custom suggestion
      customSuggestion.appendChild(suggestionText);
customSuggestion.appendChild(suggestionIn);      customSuggestion.appendChild(suggestionImage);

      // Insert the custom suggestion after the third suggestion
      suggestionsContainer.insertBefore(customSuggestion, suggestionsContainer.children[3]);
    }
  });
}

// Call the function to initialize the event listener on page load
document.addEventListener('DOMContentLoaded', handleSearchInput);

handleSearchInput();

