/* Overlay for background shadow */
.cta-overlay {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background-color: rgba(0, 0, 0, 0.5); /* Semi-transparent background */
  z-index: 9998;
  display: flex;
  justify-content: center;
  align-items: center;
}

/* Popup container */
.cta-container {
  position: relative;
  width: 80%; /* Default width for mobile screens */
  max-width: 400px;
  background-color: white;
  color: black;
  padding: 20px;
  box-shadow: 0px 0px 15px rgba(0, 0, 0, 0.3);
  z-index: 9999;
  border-radius: 8px;
}

/* Headline styles */
.cta-container h2 {
  margin: 0;
  font-size: 18px;
  color: #333;
  font-family: Arial, sans-serif;
  font-weight: 700;
  line-height: normal;
}

/* Headline CTA styles */
.cta-container h2.hCTA {
  margin-top: 0.4em;
  font-size: 15px;
  color: #333;
  font-family: Arial, sans-serif;
  font-weight: 400;
  line-height: normal;
}

/* Subheadline styles */
.cta-container p {
  color: #000;
  font-family: Arial, sans-serif;
  font-size: 15px;
  font-weight: 400;
  line-height: 130%; /* 19.5px */
  margin-top: 1.2em;
  margin-bottom: 1.2em;
}

/* Subheadline items styles */
.subheadline-item {
  display: block;
  padding-bottom: 6px;
}



/* Base Button styles */
.cta-button {
  background-color: #0058C5;
  color: white;
  text-decoration: none;
  border-radius: 4px;
  cursor: pointer;
  display: inline-block;
  line-height: normal;
  font-family: Arial, sans-serif;
  padding: 7px 19px; /* Default for desktop */
  font-size: 15px; /* Default for desktop */
  font-weight: 400;
}

/* Hover effect for button */
.cta-button:hover {
  background-color: #0048a3; /* Darker shade of blue */
  color: #fff; /* Ensure text stays white */
}

/* Close button (X) */
.cta-close {
  font-size: 24px;
  cursor: pointer;
  position: absolute;
  top: 10px;
  right: 15px;
color: #4B505D;
}

/* Responsive design for mobile */
@media (max-width: 768px) {
  /* Popup size for mobile */
  .cta-container {
    width: 90%; /* Larger width for mobile */
  }

  /* Adjust button size for mobile */
  .cta-button {
    padding: 7px 19px; /* Smaller padding for mobile */
    font-size: 15px; /* Smaller font size for mobile */
  }
}

/* Responsive design for tablets */
@media (min-width: 768px) and (max-width: 1024px) {
  .cta-container {
    width: 60%; /* Width for tablets */
  }

  .cta-button {
    padding: 8px 22px; /* Slightly smaller padding for tablets */
    font-size: 16px; /* Font size adjustment for tablets */
  }
}

