(function () {
  const showPopupOnce = false;
  const showPopupAfterPurchase = true;
  const popupShown = localStorage.getItem('popupShown');
  const purchaseMade = localStorage.getItem('purchaseMade');

  const isCabinetPage = () =>
    window.location.href.includes('/cabinet');

  if (!isCabinetPage()) return;
  if (showPopupOnce && popupShown) return;
  if (!showPopupAfterPurchase && purchaseMade) return;

  function createCTABanner() {
    if (document.querySelector('.cta-container')) return;

    const overlay = document.createElement('div');
    overlay.classList.add('cta-overlay');

    const ctaContainer = document.createElement('div');
    ctaContainer.classList.add('cta-container');

    const textContainer = document.createElement('div');
    const lang = document.documentElement.lang;

    const headline = document.createElement('h2');
    headline.textContent = (lang === 'ru')
      ? 'Получайте больше откликов на вакансии'
      : 'Primește mai multe răspunsuri la anunțuri';

    const headlineCTA = document.createElement('h2');
    headlineCTA.className = 'hCTA';
    headlineCTA.textContent = (lang === 'ru')
      ? 'Подключите тариф Premium!'
      : 'Activează tariful Premium!';

    const subheadline = document.createElement('p');
    subheadline.innerHTML = (lang === 'ru') ? `
      <span class="subheadline-item">✅ Соискатели охотнее откликаются на вакансии от проверенных компаний</span>
      <span class="subheadline-item">✅ Тариф Premium даёт на 30% больше откликов</span>
      <span class="subheadline-item">✅ Вакансии закрываются быстрее</span>
      <span class="subheadline-item">✅ Подключение юрлица — бесплатно</span>
    ` : `
      <span class="subheadline-item">✅ Candidații reacționează mai activ la companii verificate</span>
      <span class="subheadline-item">✅ Tariful Premium oferă cu 30% mai multe aplicări</span>
      <span class="subheadline-item">✅ Pozițiile se închid mai rapid</span>
      <span class="subheadline-item">✅ Conectarea companiei juridice — gratuită</span>
    `;

    textContainer.appendChild(headline);
    textContainer.appendChild(headlineCTA);
    textContainer.appendChild(subheadline);

    const button = document.createElement('a');
    button.textContent = (lang === 'ru') 
      ? 'Перейти к тарифу Premium' 
      : 'Vezi tariful Premium';
    button.href = (lang === 'ru')
      ? 'https://business.999.md/ru/tariffs/?utm_source=999&utm_medium=popup&utm_campaign=gb_popup_premium_ru'
      : 'https://business.999.md/ro/tariffs/?utm_source=999&utm_medium=popup&utm_campaign=gb_popup_premium_ro';
    button.target = '_blank';
    button.classList.add('cta-button');
    button.addEventListener('click', () => localStorage.setItem('purchaseMade', 'true'));

    const closeButton = document.createElement('span');
    closeButton.textContent = '×';
    closeButton.classList.add('cta-close');
    closeButton.addEventListener('click', () => {
      overlay.remove();
      if (showPopupOnce) localStorage.setItem('popupShown', 'true');
    });

    ctaContainer.appendChild(textContainer);
    ctaContainer.appendChild(button);
    ctaContainer.appendChild(closeButton);
    overlay.appendChild(ctaContainer);
    document.body.appendChild(overlay);
  }

  const observer = new MutationObserver(() => {
    const targetReady = document.querySelector('div[data-sentry-component="CabinetHeader"]') || document.querySelector('#__next');
    if (targetReady) {
      observer.disconnect();
      createCTABanner();
    }
  });

  observer.observe(document.body, {
    childList: true,
    subtree: true
  });
})();

(function () {
  const MAX_ATTEMPTS = 30;
  let attempts = 0;

  const waitForElements = setInterval(() => {
    const priceBlock = document.querySelector('.styles_price__ppZyo');
    const allButtons = document.querySelectorAll('.styles_actions__uerey button');
    const sendMessageButton = Array.from(allButtons).find(btn =>
      btn.textContent.trim().toLowerCase().includes('trimite mesajul') ||
      btn.textContent.trim().toLowerCase().includes('отправить сообщение')
    );

    attempts++;

    if ((priceBlock && sendMessageButton) || attempts >= MAX_ATTEMPTS) {
      clearInterval(waitForElements);
      if (!priceBlock || !sendMessageButton) return;

      const buttonText = sendMessageButton.textContent.trim().toLowerCase();
      const lang = buttonText.includes('trimite mesajul') ? 'ro' : 'ru';

      const i18n = {
        ru: {
          label: 'Предложите свою цену',
          placeholderPrefix: 'Например,',
          error: 'Введите корректную цену меньше текущей.',
          message: (value, currency) => `Здравствуйте, я хочу предложить ${value} ${currency}.`
        },
        ro: {
          label: 'Propune un preț',
          placeholderPrefix: 'De exemplu,',
          error: 'Introduceți un preț valid și mai mic decât cel afișat.',
          message: (value, currency) => `Bună, vreau să propun ${value} ${currency}.`
        }
      };

      const priceSpan = priceBlock.querySelector('.styles_sidebar__main__DaXQC');
      let basePrice = 0;
      let currency = '€';

      if (priceSpan) {
        const priceText = priceSpan.textContent.trim();
        const match = priceText.match(/([\d\s]+)([^\d\s]+)?/);
        if (match) {
          basePrice = parseInt(match[1].replace(/\s/g, ''), 10);
          currency = match[2]?.trim() || '€';
        }
      }

      const suggestedPrice = basePrice ? Math.round(basePrice * 0.8 / 100) * 100 : '';
      const placeholder = suggestedPrice
        ? `${i18n[lang].placeholderPrefix} ${suggestedPrice.toLocaleString('ru-RU')}`
        : `${i18n[lang].placeholderPrefix} 15 000`;

      const offerContainer = document.createElement('div');
      offerContainer.style.marginTop = '20px';
      offerContainer.style.fontFamily = 'inherit';

      const label = document.createElement('div');
      label.textContent = i18n[lang].label;
      label.style.fontSize = '14px';
      label.style.fontWeight = '500';
      label.style.marginBottom = '6px';
      label.style.color = '#2c2c2c';

      const inputWrapper = document.createElement('div');
      inputWrapper.style.display = 'flex';
      inputWrapper.style.alignItems = 'center';

      const input = document.createElement('input');
      input.type = 'number';
      input.placeholder = placeholder;
      Object.assign(input.style, {
        flex: '1',
        padding: '10px 14px',
        border: '1px solid #d9dbe0',
        borderRadius: '10px',
        fontSize: '14px',
        color: '#1c1c1c',
        backgroundColor: '#fff',
        outline: 'none',
        marginRight: '6px',
        appearance: 'textfield'
      });

      const style = document.createElement('style');
      style.textContent = `
        input[type="number"]::-webkit-inner-spin-button,
        input[type="number"]::-webkit-outer-spin-button {
          -webkit-appearance: none;
          margin: 0;
        }
        input[type="number"] {
          -moz-appearance: textfield;
        }
      `;
      document.head.appendChild(style);

      const button = document.createElement('button');
      button.innerHTML = '&#8594;';
      Object.assign(button.style, {
        width: '40px',
        height: '40px',
        border: '1px solid #d9dbe0',
        borderRadius: '10px',
        backgroundColor: '#edf3ff',
        color: '#1a5aff',
        fontSize: '18px',
        cursor: 'pointer',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        flexShrink: '0'
      });

      const errorMsg = document.createElement('div');
      errorMsg.textContent = i18n[lang].error;
      errorMsg.style.color = '#d93025';
      errorMsg.style.fontSize = '13px';
      errorMsg.style.marginTop = '6px';
      errorMsg.style.display = 'none';

      button.addEventListener('click', () => {
        const offerValue = parseInt(input.value.trim(), 10);

        if (!offerValue || offerValue <= 0 || offerValue > basePrice) {
          errorMsg.style.display = 'block';
          return;
        }

        errorMsg.style.display = 'none';
        sendMessageButton.click();

        const waitForTextarea = setInterval(() => {
          const textarea = document.querySelector('textarea');
          const sendBtn = document.querySelector('button[type="submit"], .chat-send-button');

          if (textarea && sendBtn) {
            clearInterval(waitForTextarea);

            const message = i18n[lang].message(offerValue, currency);
            textarea.focus();

            try {
              document.execCommand('insertText', false, message);
            } catch (e) {
              textarea.value = message;
              textarea.dispatchEvent(new Event('input', { bubbles: true }));
            }

            setTimeout(() => {
              sendBtn.click();
            }, 200);
          }
        }, 300);
      });

      input.addEventListener('input', () => {
        if (input.value.trim()) errorMsg.style.display = 'none';
      });

      inputWrapper.appendChild(input);
      inputWrapper.appendChild(button);
      offerContainer.appendChild(label);
      offerContainer.appendChild(inputWrapper);
      offerContainer.appendChild(errorMsg);

      priceBlock.insertAdjacentElement('afterend', offerContainer);
    }
  }, 300);
})();

