(function() {
  console.log('GrowthBook: paintDaysBadge запущен');

  function paintDaysBadge() {
    // Ищем все элементы на странице
    document.querySelectorAll('body *').forEach(el => {
      const txt = el.textContent.trim();
      if (txt.startsWith('Дней до')) {
        // если внутри ссылки — красим её, иначе сам елемент
        const link = el.closest('a');
        const target = link || el;
        target.style.backgroundColor = '#ff0000';
        target.style.color = '#ffffff';
      }
    });
  }

  // Запустить сейчас
  paintDaysBadge();
  // И при любых изменениях DOM
  new MutationObserver(paintDaysBadge).observe(document.body, {
    childList: true,
    subtree: true
  });
})();

