(function() {
  // Выбираем нужный элемент по селектору
  const targetElement = document.querySelector(
    'body > div.styles_main__content__C4uIg > div > div.styles_wrapper__HuNif > table > tbody > tr:nth-child(1) > td.styles_cabinet__UWDG_'
  );

  if (targetElement) {
    // Подсвечиваем этот элемент желтым
    targetElement.style.backgroundColor = 'yellow';

    // Создаем попап
    const popup = document.createElement('div');
    popup.style.position = 'fixed';
    popup.style.bottom = '20px';
    popup.style.right = '20px';
    popup.style.padding = '20px';
    popup.style.backgroundColor = '#f8d7da';
    popup.style.border = '1px solid #f5c6cb';
    popup.style.borderRadius = '5px';
    popup.style.boxShadow = '0 4px 8px rgba(0, 0, 0, 0.1)';
    popup.style.zIndex = '1000';
    popup.style.fontFamily = 'Arial, sans-serif';

    // Тексты попапа на русском и молдавском
    const messageRU = 'Смени пакет и продай за 3 дня';
    const messageRO = 'Schimbă pachetul și vinde în 3 zile';

    // Для определения языка пользователя
    const userLanguage = navigator.language || navigator.userLanguage;

    // Добавляем текст в попап в зависимости от языка
    popup.innerHTML = `
