  margin-top: 0.4em;
  font-size: 15px;
  color: #333;
  font-family: Arial, sans-serif;
  font-weight: 400;
  line-height: normal;
}

/* Subheadline styles */
.cta-container p {
  color: #000;
  font-family: Arial, sans-serif;
  font-size: 15px;
  font-weight: 400;
  line-height: 130%; /* 19.5px */
  margin-top: 1.2em;
  margin-bottom: 1.2em;
}

/* Subheadline items styles */
.subheadline-item {
  display: block;
  padding-bottom: 6px;
}



/* Base Button styles */
.cta-button {
  background-color: #0058C5;
  color: white;
  text-decoration: none;
  border-radius: 4px;
  cursor: pointer;
  display: inline-block;
  line-height: normal;
  font-family: Arial, sans-serif;
  padding: 7px 19px; /* Default for desktop */
  font-size: 15px; /* Default for desktop */
  font-weight: 400;
}

/* Hover effect for button */
.cta-button:hover {
  background-color: #0048a3; /* Darker shade of blue */
  color: #fff; /* Ensure text stays white */
}

