.cta-close {
  font-size: 24px;
  cursor: pointer;
  position: absolute;
  top: 10px;
  right: 15px;
color: #4B505D;
}

/* Responsive design for mobile */
@media (max-width: 768px) {
  /* Popup size for mobile */
  .cta-container {
    width: 90%; /* Larger width for mobile */
