variations.js:
(function () {

  if (window.__popupAlreadyShown) return;
  window.__popupAlreadyShown = true;

  const BANNER_KEY = 'popupFullscreenBannerLastSeen';
  const APP_LINK = 'https://t.ly/app_999';
  const DAYS_INTERVAL = 7;

  const isMobile = () =>
    /Mobi|Android|iPhone|iPad|iPod/i.test(navigator.userAgent);

  const daysSinceLastShown = () => {
    const last = localStorage.getItem(BANNER_KEY);
    if (!last) return Infinity;
    return (Date.now() - parseInt(last, 10)) / (1000 * 60 * 60 * 24);
  };

  if (!isMobile()) return;
  if (daysSinceLastShown() < DAYS_INTERVAL) return;
  if (document.querySelector('.popup-app-overlay')) return;

  const lang = document.documentElement.lang || 'ru';

  const content = {
    ru: {
      downloadText: 'Скачать приложение',
      skipText: 'Не сейчас',
      bgImage: 'https://i.simpalsmedia.com/fotobank/original/026c06896566c57c25147140e82eb0e5.png'
    },
    ro: {
      downloadText: 'Descarcă aplicația',
      skipText: 'Nu acum',
      bgImage: 'https://i.simpalsmedia.com/fotobank/original/c539f83e251146e8c0367702c9f70923.png'
    }
  };

  const t = content[lang] || content['ru'];

  // 🔄 Предзагрузка фонового изображения
  const preloadImage = new Image();
  preloadImage.src = t.bgImage;

  // Показываем попап только после скролла на 300px
  const handleScroll = () => {
    if (window.scrollY >= 300) {
      window.removeEventListener('scroll', handleScroll);
      showPopup();
    }
  };

  window.addEventListener('scroll', handleScroll, { passive: true });

  function showPopup() {
    const overlay = document.createElement('div');
    overlay.className = 'popup-app-overlay';
    overlay.style.backgroundImage = `url('${t.bgImage}')`;

    const close = document.createElement('div');
    close.className = 'popup-app-close';
    close.textContent = '×';
    close.addEventListener('click', dismiss);

    const buttons = document.createElement('div');
    buttons.className = 'popup-app-buttons';

    const download = document.createElement('a');
    download.className = 'popup-btn-primary';
    download.href = APP_LINK;
    download.target = '_blank';
    download.textContent = t.downloadText;

    const skip = document.createElement('button');
    skip.className = 'popup-btn-secondary';
    skip.textContent = t.skipText;
    skip.addEventListener('click', dismiss);

    buttons.appendChild(download);
    buttons.appendChild(skip);
    overlay.appendChild(close);
    overlay.appendChild(buttons);
    document.body.appendChild(overlay);

    function dismiss() {
      localStorage.setItem(BANNER_KEY, Date.now().toString());
      overlay.remove();
    }
  }
})();

