(function () {
  // ===== Настройки: подставь свои ссылки/картинки =====
  var LINK_RO = "https://999.md/blog/4068000?utm_source=999&utm_medium=banner&utm_campaign=chart_feature_cabinet";
  var LINK_RU = "https://999.md/blog/4068049?utm_source=999&utm_medium=banner&utm_campaign=chart_feature_cabinet";

  // Рекомендуемый размер: ~1000x140 (или адаптив)
  var IMG_RO  = "https://i.simpalsmedia.com/thumbor/620x0/i.simpalsmedia.com/fotobank/original/afaaa8867022c399f90f9f172bd16feb.png";
  var IMG_RU  = "https://i.simpalsmedia.com/thumbor/620x0/i.simpalsmedia.com/fotobank/original/69a1e2d6b3fdab74e44397271b1b0617.png";

  var DESKTOP_MIN = 1024;             // только десктоп
  var TARGET_PATH_PREFIX = "/cabinet"; // таргет путь
  var BANNER_ID = "gb-cabinet-banner"; // уникальный id, чтобы не дублировать

  // ===== Хелперы =====
  function waitForElement(selector, cb) {
    var el = document.querySelector(selector);
    if (el) return cb(el);
    var obs = new MutationObserver(function () {
      var el2 = document.querySelector(selector);
      if (el2) {
        obs.disconnect();
        cb(el2);
      }
    });
    obs.observe(document.body, { childList: true, subtree: true });
  }

  function insertBannerAfterHeaderCabinetExp(headerEl) {
    // Не дублируем
    if (document.getElementById(BANNER_ID)) return;

    // Определяем язык: ro / ru (учтём ro-RO, ru-RU и т.п.)
    var lang = (document.documentElement.lang || "ru").toLowerCase();
    var isRO = lang.startsWith("ro");
    var isRU = lang.startsWith("ru");
    var href = isRO ? LINK_RO : LINK_RU;
    var src  = isRO ? IMG_RO  : IMG_RU;

    // Создаём DOM
    var wrap = document.createElement("div");
    wrap.className = "banners-block";
    wrap.id = BANNER_ID;

    var a = document.createElement("a");
    a.href = href;
    a.target = "_blank";
    a.rel = "noopener noreferrer";

    var img = document.createElement("img");
    img.src = src;
    img.alt = isRO
      ? "Grafic de trafic pe categorie — funcție nouă în Autorepublicator"
      : "График посещаемости по категории — новая функция в Авторепубликаторе";
    img.loading = "lazy";
    img.decoding = "async";

    a.appendChild(img);
    wrap.appendChild(a);

    // Вставка: сразу после .header_bar
    headerEl.parentNode.insertBefore(wrap, headerEl.nextSibling);

    // Если нужен сдвиг липкого блока — без jQuery
    var sticky = document.querySelector(".items__sticky");
    if (sticky) sticky.classList.add("changed-position");

    // Простой трекинг клика (опционально)
    a.addEventListener("click", function () {
      window.dataLayer && window.dataLayer.push({
        event: "gb_banner_click",
        banner_id: BANNER_ID,
        location: "cabinet_header",
        campaign: "chart_feature_cabinet"
      });
    });
  }

  // ===== Гейт-условия =====
  // Только кабинeт
  if (!location.pathname.startsWith(TARGET_PATH_PREFIX)) return;
  // Только десктоп
  if (window.innerWidth < DESKTOP_MIN) return;

  // Ждём появления .header_bar и вставляем
  waitForElement(".header_bar", insertBannerAfterHeaderCabinetExp);
})();

function applyPackageBlockABTest() {
   return;
  // Скрыть карточку Basic из ряда
  const basicCard = document.querySelector('label[for="package--1"]');
  if (basicCard) {
    basicCard.style.display = 'none';
  }

  // Добавить снизу переключатель с текстом и ценой, стилизованный как переключатель автопродления
  const packagesBlock = document.querySelector('.styles_packages__GEB0N');
  if (packagesBlock && basicCard) {
    if (!document.getElementById('package--1-toggle')) {
      const basicToggleContainer = document.createElement('div');
      basicToggleContainer.style.marginTop = '16px';
      basicToggleContainer.style.padding = '10px 16px';
      basicToggleContainer.style.borderTop = '1px solid #ccc';
      basicToggleContainer.style.display = 'flex';
      basicToggleContainer.style.alignItems = 'center';
      basicToggleContainer.style.justifyContent = 'space-between';

      // Текст слева
      const basicText = document.createElement('span');
      basicText.style.fontSize = '14px';
      basicText.style.color = '#444';
      basicText.style.userSelect = 'none';
      basicText.textContent = 'Подать объявление без услуг продвижения на 30 дней за ';

      // Цена с чуть другим цветом
      const priceSpan = document.createElement('span');
      priceSpan.textContent = '5 леев';
      priceSpan.style.color = '#666';
      priceSpan.style.fontWeight = '600';
      basicText.appendChild(priceSpan);

      // Создаем переключатель (toggle switch)
      const toggleLabel = document.createElement('label');
      toggleLabel.className = 'switch';
      toggleLabel.style.marginLeft = '10px';

      const toggleInput = document.createElement('input');
      toggleInput.type = 'checkbox';
      toggleInput.id = 'package--1-toggle';
      toggleInput.name = 'package_name';
      toggleInput.checked = true;

      const toggleSpan = document.createElement('span');
      toggleSpan.className = 'slider round';

      toggleLabel.appendChild(toggleInput);
      toggleLabel.appendChild(toggleSpan);

      basicToggleContainer.appendChild(basicText);
      basicToggleContainer.appendChild(toggleLabel);

      packagesBlock.appendChild(basicToggleContainer);

      // Синхронизируем реальный input сразу
      const realBasicInput = document.querySelector('#package--1');
      if (realBasicInput) {
        realBasicInput.checked = true;
      }

      // Функция для обновления цвета переключателя в зависимости от состояния
      function updateToggleColor() {
        if (toggleInput.checked) {
          toggleSpan.style.backgroundColor = '#2F80ED'; // синий цвет для включенного тоггла Basic
        } else {
          toggleSpan.style.backgroundColor = '#ccc'; // серый, когда выключен
        }
      }

      // Изначальная установка цвета
      updateToggleColor();

      // При изменении переключателя Basic обновляем цвет и реальный input
      toggleInput.addEventListener('change', () => {
        const realBasicInput = document.querySelector('#package--1');
        if (realBasicInput) {
          realBasicInput.checked = toggleInput.checked;
          if (toggleInput.checked) {
            // Снимаем выделение с других пакетов, если Basic включён
            document.querySelectorAll('input[name="package_name"]').forEach(input => {
              if (input !== realBasicInput) input.checked = false;
            });
          }
        }
        updateToggleColor();
      });

      // Если пользователь выбирает один из пакетов, выключаем переключатель Basic
      const otherPackages = document.querySelectorAll('input[name="package_name"]:not(#package--1)');
      otherPackages.forEach(input => {
        input.addEventListener('change', () => {
          if (input.checked) {
            toggleInput.checked = false;
            const realBasicInput = document.querySelector('#package--1');
            if (realBasicInput) realBasicInput.checked = false;
            updateToggleColor();
          }
        });
      });
    }
  }

  // Убираем зеленую обводку у карточки Plus, добавляем тень и лейбл "Популярный"
  const plusCard = document.querySelector('label[data-test-id="ad-form-package-plus"]');
  if (plusCard) {
    plusCard.style.border = 'none';
    plusCard.style.position = 'relative';
    plusCard.style.boxShadow = '0 4px 12px rgba(76, 175, 80, 0.5)';

    if (!plusCard.querySelector('.popular-label')) {
      const popularLabel = document.createElement('span');
      popularLabel.textContent = 'Популярный';
      popularLabel.className = 'popular-label';
      popularLabel.style.position = 'absolute';
      popularLabel.style.top = '12px';
      popularLabel.style.right = '12px';
      popularLabel.style.backgroundColor = '#4CAF50';
      popularLabel.style.color = 'white';
      popularLabel.style.fontSize = '12px';
      popularLabel.style.padding = '2px 8px';
      popularLabel.style.borderRadius = '12px';
      popularLabel.style.fontWeight = '600';
      popularLabel.style.userSelect = 'none';
      plusCard.appendChild(popularLabel);
    }

    // Удаляем зелёный текст "Популярный" рядом с названием
    const titleEl = plusCard.querySelector('.styles_package__head__title__tL7Xb');
    if (titleEl) {
      const inlineLabel = titleEl.querySelector('.popular-inline-label');
      if (inlineLabel) {
        inlineLabel.remove();
      }
    }
  }

  // Добавляем скидочные лейблы рядом с ценами для всех пакетов
  const packageFooters = document.querySelectorAll('.styles_package__footer__6_0x4');
  packageFooters.forEach(footer => {
    // Проверяем, есть ли уже лейбл скидки
    if (!footer.querySelector('.discount-label')) {
      const discountLabel = document.createElement('span');
      discountLabel.className = 'discount-label';

      // Определяем скидку в зависимости от пакета
      const packageCard = footer.closest('label[data-test-id]');
      if (packageCard) {
        const dataTestId = packageCard.getAttribute('data-test-id');
        if (dataTestId === 'ad-form-package-turbo') {
          discountLabel.textContent = '-30%';
        } else {
          discountLabel.textContent = '-20%';
        }
      } else {
        discountLabel.textContent = '-20%'; // По умолчанию
      }

      discountLabel.style.color = '#D32F2F'; // красный
      discountLabel.style.fontWeight = '600';
      discountLabel.style.marginLeft = 'auto'; // прижать к правому краю
      discountLabel.style.fontSize = '14px';
      discountLabel.style.userSelect = 'none';

      // Для правильного позиционирования — делаем flex контейнер, если его нет
      if (getComputedStyle(footer).display !== 'flex') {
        footer.style.display = 'flex';
        footer.style.alignItems = 'center';
        footer.style.justifyContent = 'flex-start';
      }
      footer.appendChild(discountLabel);
    }
  });
}

// CSS для переключателя и лейблов скидок
const style = document.createElement('style');
style.textContent = `
.switch {
  position: relative;
  display: inline-block;
  width: 40px;
  height: 22px;
}
.switch input {
  opacity: 0;
  width: 0;
  height: 0;
}
.slider {
  position: absolute;
  cursor: pointer;
  top: 0; left: 0; right: 0; bottom: 0;
  background-color: #ccc;
  transition: .4s;
  border-radius: 22px;
}
.slider:before {
  position: absolute;
  content: "";
  height: 18px;
  width: 18px;
  left: 2px;
  bottom: 2px;
  background-color: white;
  transition: .4s;
  border-radius: 50%;
}
input:checked + .slider {
  background-color: #4CAF50;
}
input:checked + .slider:before {
  transform: translateX(18px);
}

/* Новый стиль для лейбла скидки */
.discount-label {
  margin-left: auto;
}
`;
document.head.appendChild(style);

applyPackageBlockABTest();

(function() {
  // убираем дубли кнопок и модалки
  document.querySelectorAll(".gb-edit-time-btn").forEach(el => el.remove());
  document.querySelectorAll(".gb-time-modal").forEach(el => el.remove());

  // создаём модалку (скрытую по умолчанию)
  const modal = document.createElement("div");
  modal.className = "gb-time-modal";
  modal.style.cssText = `
    display: none;
    position: fixed;
    top: 0; left: 0; right: 0; bottom: 0;
    background: rgba(0,0,0,0.4);
    z-index: 9999;
    justify-content: center;
    align-items: center;
    font-family: Arial, sans-serif;
  `;
  modal.innerHTML = `
    <div style="background: #fff; border-radius: 8px; width: 400px; max-width: 90%; padding: 20px; position: relative;">
      <h2 style="margin: 0 0 10px; font-size: 18px;">Настройки Авторепубликатора</h2>
      <p style="margin: 0 0 15px; color: #444; font-size: 14px;">
        В вашем пакете включена <b>1 переопубликация в час пик</b>.<br>
        По умолчанию это <b>14:00</b>.
      </p>

      <div style="margin-bottom: 15px;">
        <p style="margin: 0 0 6px; font-size: 14px;">Выберите час пик:</p>
        <div style="display: flex; gap: 8px;">
          <button class="gb-slot-btn">08:00</button>
          <button class="gb-slot-btn selected">14:00</button>
          <button class="gb-slot-btn">20:00</button>
        </div>
      </div>

      <div style="margin-bottom: 15px;">
        <p style="margin: 0 0 6px; font-size: 14px;">или введите своё время:</p>
        <input type="time" value="14:00" class="gb-custom-time" style="padding: 6px; font-size: 14px; width: 120px;">
      </div>

      <div style="display: flex; justify-content: flex-end; gap: 10px; margin-top: 20px;">
        <button class="gb-cancel-btn" style="padding: 6px 12px; border: 1px solid #ccc; background: #f5f5f5; border-radius: 4px; cursor: pointer;">
          Отмена
        </button>
        <button class="gb-save-btn" style="padding: 6px 12px; border: none; background: #5790dc; color: #fff; border-radius: 4px; cursor: pointer;">
          Сохранить
        </button>
      </div>
    </div>
  `;
  document.body.appendChild(modal);

  // обработчики кнопок внутри модалки
  modal.querySelector(".gb-cancel-btn").addEventListener("click", () => {
    modal.style.display = "none";
  });
  modal.querySelector(".gb-save-btn").addEventListener("click", () => {
    const selected = modal.querySelector(".gb-slot-btn.selected")?.innerText || modal.querySelector(".gb-custom-time").value;
    alert("Сохранили время: " + selected);
    modal.style.display = "none";
  });
  modal.querySelectorAll(".gb-slot-btn").forEach(btn => {
    btn.style.cssText = `
      flex: 1;
      padding: 6px 0;
      border: 1px solid #ccc;
      border-radius: 4px;
      background: #f9f9f9;
      cursor: pointer;
    `;
    btn.addEventListener("click", () => {
      modal.querySelectorAll(".gb-slot-btn").forEach(b => b.classList.remove("selected"));
      btn.classList.add("selected");
      btn.style.background = "#5790dc";
      btn.style.color = "#fff";
    });
  });

  // ищем блоки и вставляем кнопку
  document.querySelectorAll(".styles_package__body__features__item__89w9e").forEach(item => {
    const textEl = item.querySelector(".styles_package__body__features__item__text__a78PW");
    if (!textEl) return;

    const txt = textEl.innerText.toLowerCase();
    if (txt.includes("авторепубликатор") || txt.includes("republicare") || txt.includes("переопубликация")) {
      if (item.nextElementSibling?.classList.contains("gb-edit-time-btn")) return;

      const btn = document.createElement("div");
      btn.className = "gb-edit-time-btn";
      btn.innerHTML = `Изменить время`;
      btn.style.cssText = `
        display: inline-block;
        margin: 4px 0 0 42px;
        padding: 2px 8px;
        font-size: 12px;
        text-align: center;
        color: #555;
        background: #f9f9f9;
        border: 1px solid #ddd;
        border-radius: 4px;
        cursor: pointer;
      `;

      item.insertAdjacentElement("afterend", btn);

      btn.addEventListener("click", () => {
        modal.style.display = "flex";
      });
    }
  });
})();
